from dataclasses import dataclass
from typing import Callable

@dataclass
class Rule:
    condition: Callable[[dict], bool]
    action: str

class SimpleReflexAgent:
    def __init__(self, rules: list[Rule]):
        self.rules = rules  # evaluated in order; first match wins

    def act(self, percept: dict) -> str:
        for rule in self.rules:
            if rule.condition(percept):
                return rule.action
        return "no-op"

# Define the agent for a simple traffic light controller
traffic_agent = SimpleReflexAgent(rules=[
    Rule(condition=lambda p: p["light"] == "red",   action="stop"),
    Rule(condition=lambda p: p["light"] == "green", action="go"),
    Rule(condition=lambda p: p["light"] == "amber", action="prepare-to-stop"),
])

print(traffic_agent.act({"light": "red"}))    # stop
print(traffic_agent.act({"light": "green"}))  # go
print(traffic_agent.act({"light": "amber"}))  # prepare-to-stop

# Spam filter: condition-action rules over email features
from dataclasses import dataclass

@dataclass
class EmailPercept:
    sender_domain: str
    subject: str
    body_word_count: int
    has_unsubscribe_link: bool
    known_spam_domains: frozenset

def classify_email(p: EmailPercept) -> str:
    # Rules evaluated top-to-bottom; first match decides
    if p.sender_domain in p.known_spam_domains:
        return "spam"
    if any(word in p.subject.lower()
           for word in ["win", "prize", "free money", "click here"]):
        return "spam"
    if p.body_word_count < 5:
        return "spam"
    if p.has_unsubscribe_link and p.body_word_count > 100:
        return "newsletter"
    return "inbox"

percept = EmailPercept(
    sender_domain="suspicious.biz",
    subject="You won a prize!",
    body_word_count=20,
    has_unsubscribe_link=False,
    known_spam_domains=frozenset(["suspicious.biz", "spam4u.net"]),
)
print(classify_email(percept))  # spam (matched first rule)

# Limitation: simple reflex fails when environment is partially observable

def broken_traffic_agent(percept: dict) -> str:
    # Sensor failure: percept["light"] is None (sensor not ready)
    if percept["light"] == "red":
        return "stop"
    if percept["light"] == "green":
        return "go"
    # No rule matches -> falls through to default
    return "no-op"  # WRONG: should stop if uncertain!

# With partial observability you need a model-based agent
# that tracks state across percepts:
class ModelBasedTrafficAgent:
    def __init__(self):
        self.last_known_light = "red"  # safe default

    def act(self, percept: dict) -> str:
        if percept["light"] is not None:
            self.last_known_light = percept["light"]
        # Use remembered state when sensor is absent
        if self.last_known_light == "green":
            return "go"
        return "stop"  # safe default for red/amber/unknown

# Conflict resolution strategy 1: first-match (default)
# Strategy 2: last-match (override rules at end of list)
# Strategy 3: all-match (collect every matching action)

from typing import Callable
from dataclasses import dataclass

@dataclass
class Rule:
    condition: Callable[[dict], bool]
    action: str

def first_match(rules: list[Rule], percept: dict) -> str:
    for r in rules:
        if r.condition(percept):
            return r.action
    return "no-op"

def last_match(rules: list[Rule], percept: dict) -> str:
    result = "no-op"
    for r in rules:
        if r.condition(percept):
            result = r.action  # keep overwriting
    return result

def all_matches(rules: list[Rule], percept: dict) -> list[str]:
    return [r.action for r in rules if r.condition(percept)]

# Example: home automation
RULES = [
    Rule(condition=lambda p: p["motion"] and p["hour"] >= 22, action="dim_lights"),
    Rule(condition=lambda p: p["motion"], action="turn_lights_on"),
    Rule(condition=lambda p: not p["motion"] and p["hour"] >= 22, action="turn_lights_off"),
]

percept = {"motion": True, "hour": 23}

# first-match: "dim_lights" (correct for late-night motion)
print(first_match(RULES, percept))   # dim_lights

# last-match: "turn_lights_on" (wrong for late night)
print(last_match(RULES, percept))    # turn_lights_on

# all-matches: both triggered
print(all_matches(RULES, percept))   # ["dim_lights", "turn_lights_on"]
# → caller must resolve conflicts (e.g. take the lowest-intensity action)

from dataclasses import dataclass, field
from typing import Callable

@dataclass(order=True)
class PrioritisedRule:
    priority: int  # lower number = higher priority
    condition: Callable[[dict], bool] = field(compare=False)
    action: str = field(compare=False)
    description: str = field(compare=False, default="")

class PriorityReflexAgent:
    def __init__(self, rules: list[PrioritisedRule]):
        # Always evaluate highest-priority rules first
        self.rules = sorted(rules)

    def act(self, percept: dict) -> str:
        for rule in self.rules:
            if rule.condition(percept):
                return rule.action
        return "no-op"

    def explain(self, percept: dict) -> tuple[str, str]:
        for rule in self.rules:
            if rule.condition(percept):
                return rule.action, rule.description
        return "no-op", "no matching rule"

# Intrusion detection agent
ids_agent = PriorityReflexAgent(rules=[
    PrioritisedRule(
        priority=1,
        condition=lambda p: p.get("port") == 22 and p.get("failed_auths", 0) > 5,
        action="block_ip",
        description="SSH brute-force detected"
    ),
    PrioritisedRule(
        priority=2,
        condition=lambda p: p.get("rate_pps", 0) > 10_000,
        action="rate_limit",
        description="High packet rate"
    ),
    PrioritisedRule(
        priority=3,
        condition=lambda p: p.get("country") not in {"US", "GB", "DE"},
        action="flag_for_review",
        description="Unusual origin country"
    ),
])

action, reason = ids_agent.explain({
    "port": 22, "failed_auths": 8, "rate_pps": 500, "country": "CN"
})
print(f"{action}: {reason}")  # block_ip: SSH brute-force detected
